var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLDIER_NPC_STAY_B","text":{"KOREA":"저 녀석들…. 관리국에서 온 녀석들이잖아?","JPN":"あいつら……管理局のやつらだ。","ENG":"Aren't those people... from the Administration?","TWN":"那些…是管理局的人吧？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"SOLDIER_NPC_STAY_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_STAY_A","text":{"KOREA":"게다가 시니어까지 온 모양이야. 분위기가 심상치 않은데.","JPN":"しかもシニアまで来たようだぞ。尋常じゃねえな。","ENG":"I heard there's a Senior there as well. Things aren't looking so good, are they?","TWN":"而且連Senior都出馬咧，感覺不太對喔。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"SOLDIER_NPC_STAY_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_STAY_A","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"설마 여기 관리국에 찍힌 회사였어?","JPN":"まさかここ、管理局に目をつけられてる会社だったのか？","ENG":"Wait a sec... this company's on bad terms with the Administration?","TWN":"難道這間公司被管理局盯上了嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장…. 이래서 헤드헌터들은 믿을 게 못 된다니까.","JPN":"くそ……これだからヘッドハンターは信用できないんだよ。","ENG":"Dammit... Should've known better than to listen to headhunters.","TWN":"可惡…那些獵人頭的話真的不可信！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으, 응? 분위기가 갑자기 왜 이래? 뭐가 어떻게 돌아가는 거야?","JPN":"う、うん？　この雰囲気は何？　何がどうなってるのよ？","ENG":"H-huh? What's happening? Why's everyone leaving all of a sudden?","TWN":"欸？嗯？氣氛怎麼突然變這樣？是發生什麼事？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_NPC_STAY_A","text":{"KOREA":"이봐, 슈퍼 루키! 경력 절단 나고 싶지 않으면 빨리 움직여!","JPN":"おい、スーパールーキー！　キャリア中断になりたくなかったら早く動け！","ENG":"Hey, Super Rookie! If you don't want your career to end, you'd better move fast too!","TWN":"喂，超級新生！不想履歷表上有汙點的話，就趕快閃人吧！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_STAY_B","text":{"KOREA":"뭐 해, 어서 가자고!","JPN":"何してんだよ、早く行こうぜ！","ENG":"C'mon! We gotta get outta here!","TWN":"還想什麼？快走吧！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우, 우와악! 밀지 마! 밀지 말라니까, 이 인간들아!","JPN":"う、うわああ！　押さないで！　押さないでってば、こら！","ENG":"W-whoa! Don't push! I said, stop pushing!","TWN":"欸欸欸！不要推啦！喂，就叫你們不要推！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"내 면접을 방해하는 거냐! 저리 비키지 못해?! 야!! 잠깐만요! 야!","JPN":"私の面接を邪魔する気！　どきなさいよ！！　ちょっと！！　待ちなさい！　ちょっと！","ENG":"Get out of my way! Why are you interfering with my interview?! H-hey! WAIT!!","TWN":"想妨礙我面試是不是！還不給我滾開？！走開啦！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"갸아아아아악!","JPN":"ぎゃあああああ！","ENG":"GAAAH!","TWN":"啊啊啊啊！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"늦어서 죄송합니다! 지금부터 번호대로 면접 진행하도록 하겠습니다!","JPN":"遅くなって申し訳ありません！　今から番号順に面接を開始します！","ENG":"We're terribly sorry for the delay! We will begin the interviews in order!","TWN":"抱歉，讓大家久等了！接下來就會按照號碼開始進行面試！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…아무도 없어. 배가 고파서 다들 갔나 봐.","JPN":"……誰もいない。お腹が空いてみんな帰ったみたい。","ENG":"No one's here. Maybe they got hungry and left.","TWN":"…一個人都沒有，可能是肚子餓先走了吧。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"채용은 포기하셔야겠네요, 사장님.","JPN":"採用はあきらめないといけませんね、社長。","ENG":"I guess we should give up hiring, Boss.","TWN":"老闆，看來是要放棄徵人了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"관리국과 트러블이 생긴 회사에 지원할 바보는 세상에 한 명뿐일 걸요.","JPN":"管理局とトラブルのある会社に志願するバカはこの世界に一人しかいないと思うけど。","ENG":"There's only one person I know who would apply for a company that is on bad terms with the Administration.","TWN":"明知道公司和管理局不合還願意來面試的人，全世界只有一個。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 왜 날 보고 말하냐? 듣는 사람 기분 나쁘게.","JPN":"おい、なんでこっち見ながら言ってんだよ？　気分悪いだろ。","ENG":"Huh? Why are you looking at me for? I feel offended.","TWN":"喂，你幹嘛看著我講？感覺很差欸！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};